import Sidebar from '../components/Sidebar';
import startImage from '../assets/startpage.png';

function MainPage() {
  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden">
      {/* 페이지 내용 */}
      <div className="relative z-10 flex px-8 pt-12 items-start">
        {/* 사이드바 */}
        <Sidebar />

        {/* 오른쪽 메인 콘텐츠 */}
        <main className="flex-1 relative flex items-center justify-center min-h-[90vh]">
          
          {/* 중앙 배경 이미지 (선명하게) */}
          <img
            src={startImage}
            alt="배경"
            className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 max-w-[80%] max-h-[80%] pointer-events-none"
          />

          {/* 콘텐츠 카드들 */}
          <div className="relative z-10 w-full max-w-2xl space-y-6">
            <h2 className="text-sm text-blue-600 bg-blue-100 rounded-full px-4 py-2 text-center">
              오늘의 부동산 관련 지식 한 줄 팝업
            </h2>

            {/* 카드 리스트 */}
            {[
              '부동산 관련 정보 제공',
              '부동산 관련 퀴즈',
              '부동산 지원 정책',
            ].map((text, idx) => (
              <div
                key={idx}
                className="bg-white border border-blue-200 rounded-2xl shadow px-6 py-5 flex items-center justify-between"
              >
                <p className="text-lg font-medium">{text}</p>
                <button className="px-4 py-2 text-white bg-blue-600 rounded-md hover:bg-blue-700 transition">
                  바로가기
                </button>
              </div>
            ))}
          </div>

        </main>
      </div>
    </div>
  );
}

export default MainPage;
